# =============================================================================
# ── SKILL SCORE FUNCTION ──────────────────────────────────────────────────────
# =============================================================================
def compute_scores(obs_z, obs_v, mod_z, mod_v, z_min=None, z_max=None):
    mask = np.ones(len(obs_z), dtype=bool)
    if z_min is not None: mask &= obs_z >= z_min
    if z_max is not None: mask &= obs_z <= z_max
    oz, ov = obs_z[mask], obs_v[mask]
    if len(oz) < 2:
        return dict(RMSE=np.nan, R2=np.nan)
    f   = interp1d(mod_z, mod_v, bounds_error=False, fill_value='extrapolate')
    pv  = f(oz)
    res = ov - pv
    rmse = np.sqrt(np.mean(res**2))
    ss_res = np.sum(res**2)
    ss_tot = np.sum((ov - np.mean(ov))**2)
    r2 = 1 - ss_res / ss_tot if ss_tot > 0 else np.nan
    return dict(RMSE=rmse, R2=r2)

